def find(id: Int): Option[String] =
  if (id == 1) Some("Ada") else None

val name = find(1).map(_.toUpperCase).getOrElse("unknown")
println(name) // ADA

find(2) match {
  case Some(n) => println(n)
  case None    => println("missing")
}

val result =
  for {
    a <- Some(2)
    b <- Some(3)
    if a < b
  } yield a + b
println(result) // Some(5)

