// recursive method needs explicit return type
def fact(n: Int): Int = if (n <= 1) 1 else n * fact(n - 1)

import scala.concurrent.Future
import scala.concurrent.ExecutionContext.Implicits.global

val f: Future[Int] = Future { 21 * 2 }
val g = f.map(_ + 1).recover { case _ => -1 }
g.foreach(println) // 43

val half: PartialFunction[Int, Int] = {
  case x if x % 2 == 0 => x / 2
}

println(half.isDefinedAt(4)) // true
val r = List(1, 2, 3, 4).collect(half) // List(1, 2)

import scala.annotation.tailrec

@tailrec
def sum(xs: List[Int], acc: Int = 0): Int = xs match {
  case Nil     => acc
  case h :: t  => sum(t, acc + h) // tail position
}

println(sum(List(1, 2, 3, 4))) // 10

def add(a: Int)(b: Int): Int = a + b
val add5 = add(5) _   // partially applied: Int => Int
println(add5(10))     // 15

def repeat(n: Int)(f: => Unit): Unit = (1 to n).foreach(_ => f)
repeat(2) { println("hi") }

object Email {
  def unapply(s: String): Option[(String, String)] =
    s.split("@") match {
      case Array(user, domain) => Some((user, domain))
      case _                   => None
    }
}

"ada@x.com" match {
  case Email(user, domain) => println(s"$user at $domain")
  case _                   => println("invalid")
}

def parse(s: String): Either[String, Int] =
  s.toIntOption.toRight(s"invalid: $s")

val result =
  for {
    a <- parse("2")
    b <- parse("3")
  } yield a + b

println(result.fold(err => s"Error $err", n => s"Ok $n")) // Ok 5
println(List(1, 2, 3).fold(0)(_ + _)) // 6
